var COURSE_PL_IT = [{day: 1, title: `Pierwsze pozdrowienia`, title_native: `Primi saluti`, focus: `Zaczynasz od najprostszych zwrotów, których użyjesz od razu po przyjeździe do Rzymu, Mediolanu lub Florencji. Nauczysz się witać, żegnać i mówić uprzejmie do obcych osób.`, vocab: [{it: `ciao`, pl: `cześć`, ipa: `/czao/`},{it: `buongiorno`, pl: `dzień dobry`, ipa: `/bu-on-dżior-no/`},{it: `buonasera`, pl: `dobry wieczór`, ipa: `/bu-o-na-se-ra/`},{it: `arrivederci`, pl: `do widzenia`, ipa: `/ar-ri-we-der-czi/`},{it: `sì`, pl: `tak`, ipa: `/si/`},{it: `no`, pl: `nie`, ipa: `/no/`},{it: `per favore`, pl: `proszę`, ipa: `/per fa-wo-re/`},{it: `grazie`, pl: `dziękuję`, ipa: `/gra-cje/`},{it: `prego`, pl: `proszę, nie ma za co`, ipa: `/pre-go/`},{it: `scusi`, pl: `przepraszam pana/panią`, ipa: `/sku-zi/`}], phrases: [{it: `Ciao!`, pl: `Cześć!`, ipa: `/czao/`},{it: `Buongiorno!`, pl: `Dzień dobry!`, ipa: `/bu-on-dżior-no/`},{it: `Buonasera!`, pl: `Dobry wieczór!`, ipa: `/bu-o-na-se-ra/`},{it: `Arrivederci!`, pl: `Do widzenia!`, ipa: `/ar-ri-we-der-czi/`},{it: `Grazie mille.`, pl: `Bardzo dziękuję.`, ipa: `/gra-cje mil-le/`},{it: `Scusi, per favore.`, pl: `Przepraszam, proszę.`, ipa: `/sku-zi per fa-wo-re/`}], grammar: `W języku włoskim często wybierasz między stylem nieformalnym i formalnym. Ciao jest dobre wśród znajomych, ale w sklepie, hotelu czy restauracji bezpieczniej powiedzieć buongiorno albo buonasera. Scusi to uprzejme „przepraszam”, gdy zwracasz się do obcej osoby.`, practice: [`Powiedz po włosku „dzień dobry” do recepcjonisty w hotelu.`,`Powiedz „dziękuję bardzo” po otrzymaniu kawy.`,`Wybierz właściwe powitanie: ciao czy buongiorno w rozmowie z nieznanym sprzedawcą.`,`Przećwicz krótką wymianę: dzień dobry, dziękuję, do widzenia.`,`Powiedz po włosku „przepraszam, proszę” przed zadaniem pytania.`]},{day: 2, title: `Przedstawianie się`, title_native: `Presentarsi`, focus: `W Wenecji lub Bolonii łatwo spotkać innych podróżnych, gospodarzy i przewodników. Nauczysz się mówić, jak masz na imię, skąd jesteś i że miło ci kogoś poznać.`, vocab: [{it: `io`, pl: `ja`, ipa: `/jo/`},{it: `tu`, pl: `ty`, ipa: `/tu/`},{it: `lui`, pl: `on`, ipa: `/lui/`},{it: `lei`, pl: `ona; pan/pani`, ipa: `/lej/`},{it: `nome`, pl: `imię`, ipa: `/no-me/`},{it: `Polonia`, pl: `Polska`, ipa: `/po-lo-nia/`},{it: `italiano`, pl: `włoski`, ipa: `/i-ta-lia-no/`},{it: `polacco`, pl: `polski`, ipa: `/po-lak-ko/`},{it: `piacere`, pl: `miło mi`, ipa: `/pia-cze-re/`},{it: `sono`, pl: `jestem`, ipa: `/so-no/`}], phrases: [{it: `Mi chiamo Anna.`, pl: `Nazywam się Anna.`, ipa: `/mi kia-mo an-na/`},{it: `Sono polacco.`, pl: `Jestem Polakiem.`, ipa: `/so-no po-lak-ko/`},{it: `Sono polacca.`, pl: `Jestem Polką.`, ipa: `/so-no po-lak-ka/`},{it: `Vengo dalla Polonia.`, pl: `Pochodzę z Polski.`, ipa: `/wen-go dal-la po-lo-nia/`},{it: `Piacere.`, pl: `Miło mi.`, ipa: `/pia-cze-re/`},{it: `Come ti chiami?`, pl: `Jak się nazywasz?`, ipa: `/ko-me ti kia-mi/`}], grammar: `Włoskie czasowniki zmieniają formę w zależności od osoby, ale na początku wystarczy zapamiętać sono jako „jestem”. Zwróć uwagę na rodzaj: polacco mówi mężczyzna, polacca mówi kobieta. Włoskie ch zapisuje się jak polskie „k”, więc chiamo brzmi /kia-mo/.`, practice: [`Przedstaw się po włosku swoim imieniem.`,`Powiedz, że pochodzisz z Polski.`,`Zapytaj drugą osobę, jak się nazywa.`,`Odpowiedz „miło mi” po poznaniu kogoś.`,`Ułóż krótką wypowiedź: „Dzień dobry, nazywam się…, jestem z Polski.”`]},{day: 3, title: `Uprzejme prośby i podstawowe pytania`, title_native: `Richieste gentili e domande di base`, focus: `W Neapolu lub Palermo wiele sytuacji zaczyna się od prostego pytania. Nauczysz się pytać „gdzie”, „ile” i „czy mogę”, zachowując uprzejmy ton.`, vocab: [{it: `dove`, pl: `gdzie`, ipa: `/do-we/`},{it: `quando`, pl: `kiedy`, ipa: `/kuan-do/`},{it: `quanto`, pl: `ile`, ipa: `/kuan-to/`},{it: `che cosa`, pl: `co`, ipa: `/ke ko-za/`},{it: `qui`, pl: `tutaj`, ipa: `/kui/`},{it: `lì`, pl: `tam`, ipa: `/li/`},{it: `adesso`, pl: `teraz`, ipa: `/a-des-so/`},{it: `posso`, pl: `mogę`, ipa: `/pos-so/`},{it: `aiuto`, pl: `pomoc`, ipa: `/a-ju-to/`},{it: `bagno`, pl: `łazienka`, ipa: `/ba-nio/`}], phrases: [{it: `Dov'è il bagno?`, pl: `Gdzie jest łazienka?`, ipa: `/do-we il ba-nio/`},{it: `Quanto costa?`, pl: `Ile to kosztuje?`, ipa: `/kuan-to kos-ta/`},{it: `Posso entrare?`, pl: `Czy mogę wejść?`, ipa: `/pos-so en-tra-re/`},{it: `Che cosa significa?`, pl: `Co to znaczy?`, ipa: `/ke ko-za si-ni-fi-ka/`},{it: `Ho bisogno di aiuto.`, pl: `Potrzebuję pomocy.`, ipa: `/o bi-zo-nio di a-ju-to/`},{it: `È qui?`, pl: `Czy to tutaj?`, ipa: `/e kui/`}], grammar: `W pytaniach po włosku często wystarczy zmienić intonację, bez dodatkowego słowa jak polskie „czy”. Quanto costa? dosłownie znaczy „ile kosztuje?”. Dov'è to skrót od dove è, czyli „gdzie jest”.`, practice: [`Zapytaj po włosku, gdzie jest łazienka.`,`Zapytaj o cenę pamiątki.`,`Powiedz, że potrzebujesz pomocy.`,`Zapytaj, czy możesz wejść.`,`Przećwicz pytanie „czy to tutaj?” w kontekście wejścia do muzeum.`]},{day: 4, title: `Liczby i ceny`, title_native: `Numeri e prezzi`, focus: `Na targu w Turynie lub w sklepie z pamiątkami w Rzymie liczby są niezbędne. Nauczysz się liczyć, rozumieć ceny i pytać o koszt.`, vocab: [{it: `uno`, pl: `jeden`, ipa: `/u-no/`},{it: `due`, pl: `dwa`, ipa: `/du-e/`},{it: `tre`, pl: `trzy`, ipa: `/tre/`},{it: `quattro`, pl: `cztery`, ipa: `/kuat-tro/`},{it: `cinque`, pl: `pięć`, ipa: `/czin-kue/`},{it: `sei`, pl: `sześć`, ipa: `/sej/`},{it: `sette`, pl: `siedem`, ipa: `/set-te/`},{it: `otto`, pl: `osiem`, ipa: `/ot-to/`},{it: `nove`, pl: `dziewięć`, ipa: `/no-we/`},{it: `dieci`, pl: `dziesięć`, ipa: `/die-czi/`}], phrases: [{it: `Costa cinque euro.`, pl: `To kosztuje pięć euro.`, ipa: `/kos-ta czin-kue eu-ro/`},{it: `Due biglietti, per favore.`, pl: `Dwa bilety, proszę.`, ipa: `/du-e bi-lie-tti per fa-wo-re/`},{it: `Ho dieci euro.`, pl: `Mam dziesięć euro.`, ipa: `/o die-czi eu-ro/`},{it: `Solo uno, grazie.`, pl: `Tylko jeden, dziękuję.`, ipa: `/so-lo u-no gra-cje/`},{it: `Quanto viene?`, pl: `Ile wychodzi?`, ipa: `/kuan-to wje-ne/`},{it: `Sono otto euro.`, pl: `To osiem euro.`, ipa: `/so-no ot-to eu-ro/`}], grammar: `Rzeczowniki po włosku zwykle mają liczbę pojedynczą i mnogą: biglietto to jeden bilet, biglietti to bilety. Euro w codziennej mowie często zostaje bez zmiany po liczbach. Przy zamawianiu wystarczy liczba plus rzeczownik: due biglietti.`, practice: [`Policz od 1 do 10 po włosku.`,`Zamów dwa bilety.`,`Powiedz, że masz dziesięć euro.`,`Zapytaj, ile wychodzi rachunek.`,`Odpowiedz sprzedawcy: „tylko jeden, dziękuję.”`]},{day: 5, title: `W kawiarni`, title_native: `Al bar`, focus: `We Włoszech bar często oznacza kawiarnię, gdzie rano pije się espresso przy ladzie. Nauczysz się zamawiać kawę, wodę i prostą przekąskę w miejscu takim jak Florencja.`, vocab: [{it: `caffè`, pl: `kawa, espresso`, ipa: `/kaf-fe/`},{it: `cappuccino`, pl: `cappuccino`, ipa: `/kap-pu-czi-no/`},{it: `acqua`, pl: `woda`, ipa: `/ak-kua/`},{it: `cornetto`, pl: `rogalik`, ipa: `/kor-net-to/`},{it: `zucchero`, pl: `cukier`, ipa: `/dzuk-ke-ro/`},{it: `latte`, pl: `mleko`, ipa: `/lat-te/`},{it: `tavolo`, pl: `stolik`, ipa: `/ta-wo-lo/`},{it: `banco`, pl: `lada`, ipa: `/ban-ko/`},{it: `caldo`, pl: `gorący`, ipa: `/kal-do/`},{it: `freddo`, pl: `zimny`, ipa: `/fred-do/`}], phrases: [{it: `Un caffè, per favore.`, pl: `Espresso, proszę.`, ipa: `/un kaf-fe per fa-wo-re/`},{it: `Un cappuccino e un cornetto.`, pl: `Cappuccino i rogalik.`, ipa: `/un kap-pu-czi-no e un kor-net-to/`},{it: `Acqua naturale, per favore.`, pl: `Woda niegazowana, proszę.`, ipa: `/ak-kua na-tu-ra-le per fa-wo-re/`},{it: `Con zucchero?`, pl: `Z cukrem?`, ipa: `/kon dzuk-ke-ro/`},{it: `Al banco o al tavolo?`, pl: `Przy ladzie czy przy stoliku?`, ipa: `/al ban-ko o al ta-wo-lo/`},{it: `Il conto, per favore.`, pl: `Rachunek, proszę.`, ipa: `/il kon-to per fa-wo-re/`}], grammar: `We włoskim przed rzeczownikiem często pojawia się rodzajnik: un caffè, un cornetto, il conto. Na początku ucz się ich razem z całymi zwrotami. W kawiarni możesz usłyszeć al banco, czyli „przy ladzie”, albo al tavolo, czyli „przy stoliku”.`, practice: [`Zamów espresso i rogalik.`,`Poproś o wodę niegazowaną.`,`Odpowiedz, czy chcesz przy ladzie czy przy stoliku.`,`Poproś o rachunek.`,`Przećwicz krótkie zamówienie śniadaniowe w kawiarni.`]},{day: 6, title: `Jedzenie i proste zamówienia`, title_native: `Cibo e ordini semplici`, focus: `W trattorii w Bolonii lub małej restauracji w Sienie warto umieć zamówić prosto i jasno. Poznasz słowa związane z jedzeniem i podstawowe prośby przy stole.`, vocab: [{it: `pane`, pl: `chleb`, ipa: `/pa-ne/`},{it: `pasta`, pl: `makaron`, ipa: `/pas-ta/`},{it: `pizza`, pl: `pizza`, ipa: `/pit-tsa/`},{it: `insalata`, pl: `sałatka`, ipa: `/in-sa-la-ta/`},{it: `formaggio`, pl: `ser`, ipa: `/for-mad-dżo/`},{it: `carne`, pl: `mięso`, ipa: `/kar-ne/`},{it: `pesce`, pl: `ryba`, ipa: `/pe-sze/`},{it: `vino`, pl: `wino`, ipa: `/wi-no/`},{it: `menu`, pl: `menu`, ipa: `/me-nu/`},{it: `piatto`, pl: `danie; talerz`, ipa: `/piat-to/`}], phrases: [{it: `Vorrei una pizza.`, pl: `Chciałbym/chciałabym pizzę.`, ipa: `/wor-rej u-na pit-tsa/`},{it: `Vorrei la pasta.`, pl: `Chciałbym/chciałabym makaron.`, ipa: `/wor-rej la pas-ta/`},{it: `Il menu, per favore.`, pl: `Menu, proszę.`, ipa: `/il me-nu per fa-wo-re/`},{it: `Senza formaggio, per favore.`, pl: `Bez sera, proszę.`, ipa: `/sen-dza for-mad-dżo per fa-wo-re/`},{it: `Che cosa consiglia?`, pl: `Co pan/pani poleca?`, ipa: `/ke ko-za kon-si-lia/`},{it: `È molto buono.`, pl: `To jest bardzo dobre.`, ipa: `/e mol-to bu-o-no/`}], grammar: `Vorrei to bardzo przydatna forma grzecznościowa: znaczy „chciałbym/chciałabym”. Jest uprzejmiejsze niż voglio, czyli „chcę”. Senza oznacza „bez” i działa prosto: senza formaggio, senza carne, senza zucchero.`, practice: [`Zamów pizzę za pomocą vorrei.`,`Poproś o menu.`,`Powiedz „bez sera, proszę”.`,`Zapytaj kelnera, co poleca.`,`Powiedz, że danie jest bardzo dobre.`]},{day: 7, title: `Napoje i preferencje`, title_native: `Bevande e preferenze`, focus: `Podczas kolacji w Weronie albo przerwy w podróży po Toskanii często zamawiasz napoje. Nauczysz się mówić, co lubisz, czego nie chcesz i jaki napój wybierasz.`, vocab: [{it: `bevanda`, pl: `napój`, ipa: `/be-wan-da/`},{it: `acqua frizzante`, pl: `woda gazowana`, ipa: `/ak-kua frit-dzan-te/`},{it: `birra`, pl: `piwo`, ipa: `/bir-ra/`},{it: `succo`, pl: `sok`, ipa: `/suk-ko/`},{it: `tè`, pl: `herbata`, ipa: `/te/`},{it: `limone`, pl: `cytryna`, ipa: `/li-mo-ne/`},{it: `ghiaccio`, pl: `lód`, ipa: `/giat-czio/`},{it: `bicchiere`, pl: `szklanka`, ipa: `/bik-kie-re/`},{it: `bottiglia`, pl: `butelka`, ipa: `/bot-ti-lia/`},{it: `mi piace`, pl: `lubię`, ipa: `/mi pia-cze/`}], phrases: [{it: `Mi piace il vino rosso.`, pl: `Lubię czerwone wino.`, ipa: `/mi pia-cze il wi-no ros-so/`},{it: `Non mi piace la birra.`, pl: `Nie lubię piwa.`, ipa: `/non mi pia-cze la bir-ra/`},{it: `Una bottiglia d'acqua, per favore.`, pl: `Butelkę wody, proszę.`, ipa: `/u-na bot-ti-lia dak-kua per fa-wo-re/`},{it: `Senza ghiaccio, grazie.`, pl: `Bez lodu, dziękuję.`, ipa: `/sen-dza giat-czio gra-cje/`},{it: `Con limone, per favore.`, pl: `Z cytryną, proszę.`, ipa: `/kon li-mo-ne per fa-wo-re/`},{it: `Prendo un tè.`, pl: `Wezmę herbatę.`, ipa: `/pren-do un te/`}], grammar: `Mi piace dosłownie znaczy „podoba mi się”, ale po polsku często tłumaczymy to jako „lubię”. Przy jednej rzeczy mówimy mi piace, a przy wielu mi piacciono, ale na razie zapamiętaj najprostszy wzór: mi piace il vino. Non przed czasownikiem tworzy przeczenie.`, practice: [`Powiedz, że lubisz czerwone wino.`,`Powiedz, że nie lubisz piwa.`,`Zamów butelkę wody.`,`Poproś o napój bez lodu.`,`Powiedz „wezmę herbatę”.`]},{day: 8, title: `Pytanie o drogę`, title_native: `Chiedere indicazioni`, focus: `W starych uliczkach Wenecji, Genui lub Rzymu łatwo się zgubić. Nauczysz się pytać o drogę i rozumieć podstawowe kierunki.`, vocab: [{it: `strada`, pl: `ulica; droga`, ipa: `/stra-da/`},{it: `piazza`, pl: `plac`, ipa: `/piat-tsa/`},{it: `stazione`, pl: `stacja`, ipa: `/sta-cjo-ne/`},{it: `centro`, pl: `centrum`, ipa: `/czen-tro/`},{it: `destra`, pl: `prawa strona`, ipa: `/des-tra/`},{it: `sinistra`, pl: `lewa strona`, ipa: `/si-nis-tra/`},{it: `dritto`, pl: `prosto`, ipa: `/drit-to/`},{it: `vicino`, pl: `blisko`, ipa: `/wi-czi-no/`},{it: `lontano`, pl: `daleko`, ipa: `/lon-ta-no/`},{it: `mappa`, pl: `mapa`, ipa: `/map-pa/`}], phrases: [{it: `Dov'è la stazione?`, pl: `Gdzie jest stacja?`, ipa: `/do-we la sta-cjo-ne/`},{it: `Vada dritto.`, pl: `Proszę iść prosto.`, ipa: `/wa-da drit-to/`},{it: `Giri a destra.`, pl: `Proszę skręcić w prawo.`, ipa: `/dżi-ri a des-tra/`},{it: `Giri a sinistra.`, pl: `Proszę skręcić w lewo.`, ipa: `/dżi-ri a si-nis-tra/`},{it: `È vicino?`, pl: `Czy to blisko?`, ipa: `/e wi-czi-no/`},{it: `Mi può mostrare sulla mappa?`, pl: `Czy może mi pan/pani pokazać na mapie?`, ipa: `/mi puo mos-tra-re sul-la map-pa/`}], grammar: `Wskazówki w formalnej rozmowie często używają form vada i giri, czyli „proszę iść” i „proszę skręcić”. A destra i a sinistra oznaczają „w prawo” i „w lewo”. W podróży nie musisz znać całej gramatyki, wystarczy rozpoznawać te formy.`, practice: [`Zapytaj, gdzie jest stacja.`,`Powiedz komuś „proszę iść prosto”.`,`Poproś o pokazanie drogi na mapie.`,`Zapytaj, czy muzeum jest blisko.`,`Przećwicz wskazówki: prosto, w prawo, w lewo.`]},{day: 9, title: `Transport miejski`, title_native: `Trasporto pubblico`, focus: `W Mediolanie, Rzymie i Turynie korzystanie z metra, autobusu lub tramwaju jest codziennością. Nauczysz się kupować bilety i pytać o przystanki.`, vocab: [{it: `biglietto`, pl: `bilet`, ipa: `/bi-lie-tto/`},{it: `autobus`, pl: `autobus`, ipa: `/au-to-bus/`},{it: `metro`, pl: `metro`, ipa: `/me-tro/`},{it: `tram`, pl: `tramwaj`, ipa: `/tram/`},{it: `fermata`, pl: `przystanek`, ipa: `/fer-ma-ta/`},{it: `linea`, pl: `linia`, ipa: `/li-ne-a/`},{it: `andata`, pl: `przejazd w jedną stronę`, ipa: `/an-da-ta/`},{it: `ritorno`, pl: `powrót`, ipa: `/ri-tor-no/`},{it: `orario`, pl: `rozkład; godzina`, ipa: `/o-ra-rio/`},{it: `ritardo`, pl: `opóźnienie`, ipa: `/ri-tar-do/`}], phrases: [{it: `Un biglietto per la metro.`, pl: `Bilet na metro.`, ipa: `/un bi-lie-tto per la me-tro/`},{it: `Dove compro il biglietto?`, pl: `Gdzie kupię bilet?`, ipa: `/do-we kom-pro il bi-lie-tto/`},{it: `Quale linea va al centro?`, pl: `Która linia jedzie do centrum?`, ipa: `/kua-le li-ne-a wa al czen-tro/`},{it: `Questa è la fermata giusta?`, pl: `Czy to właściwy przystanek?`, ipa: `/kue-sta e la fer-ma-ta dżus-ta/`},{it: `A che ora parte?`, pl: `O której odjeżdża?`, ipa: `/a ke o-ra par-te/`},{it: `Il treno è in ritardo.`, pl: `Pociąg jest opóźniony.`, ipa: `/il tre-no e in ri-tar-do/`}], grammar: `Quale oznacza „który/która” i jest bardzo użyteczne przy wyborze linii, peronu lub drogi. Questa znaczy „ta”, więc questa fermata to „ten przystanek” albo „ta stacja” zależnie od kontekstu. Va oznacza „jedzie” lub „idzie” w sensie trasy.`, practice: [`Zapytaj, gdzie kupić bilet.`,`Poproś o bilet na metro.`,`Zapytaj, która linia jedzie do centrum.`,`Sprawdź, czy to właściwy przystanek.`,`Powiedz, że pociąg jest opóźniony.`]},{day: 10, title: `Dworzec i pociągi`, title_native: `Stazione e treni`, focus: `Podróż pociągiem z Rzymu do Florencji lub z Mediolanu do Wenecji wymaga kilku konkretnych słów. Nauczysz się pytać o peron, odjazd i miejsce w pociągu.`, vocab: [{it: `treno`, pl: `pociąg`, ipa: `/tre-no/`},{it: `binario`, pl: `peron; tor`, ipa: `/bi-na-rio/`},{it: `partenza`, pl: `odjazd`, ipa: `/par-ten-dza/`},{it: `arrivo`, pl: `przyjazd`, ipa: `/ar-ri-wo/`},{it: `posto`, pl: `miejsce`, ipa: `/pos-to/`},{it: `carrozza`, pl: `wagon`, ipa: `/kar-rot-tsa/`},{it: `valigia`, pl: `walizka`, ipa: `/wa-li-dża/`},{it: `controllore`, pl: `konduktor`, ipa: `/kon-trol-lo-re/`},{it: `prenotazione`, pl: `rezerwacja`, ipa: `/pre-no-ta-cjo-ne/`},{it: `stazione centrale`, pl: `dworzec główny`, ipa: `/sta-cjo-ne czen-tra-le/`}], phrases: [{it: `Da quale binario parte?`, pl: `Z którego peronu odjeżdża?`, ipa: `/da kua-le bi-na-rio par-te/`},{it: `Ho una prenotazione.`, pl: `Mam rezerwację.`, ipa: `/o u-na pre-no-ta-cjo-ne/`},{it: `Questo è il mio posto.`, pl: `To jest moje miejsce.`, ipa: `/kue-sto e il mio pos-to/`},{it: `Dov'è la carrozza cinque?`, pl: `Gdzie jest wagon piąty?`, ipa: `/do-we la kar-rot-tsa czin-kue/`},{it: `Il treno per Firenze parte alle nove.`, pl: `Pociąg do Florencji odjeżdża o dziewiątej.`, ipa: `/il tre-no per fi-ren-tse par-te al-le no-we/`},{it: `Posso mettere qui la valigia?`, pl: `Czy mogę tu położyć walizkę?`, ipa: `/pos-so met-te-re kui la wa-li-dża/`}], grammar: `Alle nove oznacza „o dziewiątej”, a alle używa się przy godzinach w liczbie mnogiej. Per Firenze oznacza „do Florencji”. Włoskie miasta często mają polskie odpowiedniki, ale w podróży usłyszysz nazwy włoskie: Firenze, Roma, Venezia, Milano.`, practice: [`Zapytaj, z którego peronu odjeżdża pociąg.`,`Powiedz, że masz rezerwację.`,`Zapytaj o wagon piąty.`,`Powiedz, że to twoje miejsce.`,`Zapytaj, czy możesz położyć walizkę tutaj.`]},{day: 11, title: `Hotel i zameldowanie`, title_native: `Hotel e check-in`, focus: `W hotelu w Rzymie, pensjonacie w Toskanii lub apartamencie w Bari musisz podać rezerwację i zrozumieć podstawowe informacje. Nauczysz się zwrotów przy recepcji.`, vocab: [{it: `hotel`, pl: `hotel`, ipa: `/o-tel/`},{it: `camera`, pl: `pokój`, ipa: `/ka-me-ra/`},{it: `chiave`, pl: `klucz`, ipa: `/kia-we/`},{it: `reception`, pl: `recepcja`, ipa: `/re-czep-szon/`},{it: `documento`, pl: `dokument`, ipa: `/do-ku-men-to/`},{it: `passaporto`, pl: `paszport`, ipa: `/pas-sa-por-to/`},{it: `prenotazione`, pl: `rezerwacja`, ipa: `/pre-no-ta-cjo-ne/`},{it: `notte`, pl: `noc`, ipa: `/not-te/`},{it: `colazione`, pl: `śniadanie`, ipa: `/ko-la-cjo-ne/`},{it: `ascensore`, pl: `winda`, ipa: `/a-szen-so-re/`}], phrases: [{it: `Ho una prenotazione a nome Kowalski.`, pl: `Mam rezerwację na nazwisko Kowalski.`, ipa: `/o u-na pre-no-ta-cjo-ne a no-me ko-wal-ski/`},{it: `Vorrei fare il check-in.`, pl: `Chciałbym/chciałabym się zameldować.`, ipa: `/wor-rej fa-re il czek-in/`},{it: `Dov'è la mia camera?`, pl: `Gdzie jest mój pokój?`, ipa: `/do-we la mia ka-me-ra/`},{it: `La colazione è inclusa?`, pl: `Czy śniadanie jest wliczone?`, ipa: `/la ko-la-cjo-ne e in-klu-za/`},{it: `A che piano è la camera?`, pl: `Na którym piętrze jest pokój?`, ipa: `/a ke pia-no e la ka-me-ra/`},{it: `Posso lasciare la valigia qui?`, pl: `Czy mogę zostawić tu walizkę?`, ipa: `/pos-so la-sza-re la wa-li-dża kui/`}], grammar: `A nome oznacza „na nazwisko” lub „na imię”, gdy mówisz o rezerwacji. Mia camera to „mój pokój”, ale po włosku camera jest rodzaju żeńskiego, więc używa się mia. W hotelu forma vorrei jest bardzo naturalna i uprzejma.`, practice: [`Powiedz, że masz rezerwację na swoje nazwisko.`,`Poproś o zameldowanie.`,`Zapytaj, czy śniadanie jest wliczone.`,`Zapytaj, na którym piętrze jest pokój.`,`Zapytaj, czy możesz zostawić walizkę.`]},{day: 12, title: `Problemy w hotelu`, title_native: `Problemi in hotel`, focus: `Czasem w pokoju nie działa klimatyzacja albo brakuje ręcznika. Nauczysz się spokojnie zgłaszać praktyczne problemy w hotelu w mieście takim jak Mediolan.`, vocab: [{it: `problema`, pl: `problem`, ipa: `/pro-ble-ma/`},{it: `aria condizionata`, pl: `klimatyzacja`, ipa: `/a-ria kon-di-cjo-na-ta/`},{it: `doccia`, pl: `prysznic`, ipa: `/dot-cza/`},{it: `asciugamano`, pl: `ręcznik`, ipa: `/a-szu-ga-ma-no/`},{it: `letto`, pl: `łóżko`, ipa: `/let-to/`},{it: `rumore`, pl: `hałas`, ipa: `/ru-mo-re/`},{it: `caldo`, pl: `gorąco`, ipa: `/kal-do/`},{it: `freddo`, pl: `zimno`, ipa: `/fred-do/`},{it: `rotto`, pl: `zepsuty`, ipa: `/rot-to/`},{it: `pulito`, pl: `czysty`, ipa: `/pu-li-to/`}], phrases: [{it: `C'è un problema.`, pl: `Jest problem.`, ipa: `/cze un pro-ble-ma/`},{it: `L'aria condizionata non funziona.`, pl: `Klimatyzacja nie działa.`, ipa: `/la-ria kon-di-cjo-na-ta non fun-cjo-na/`},{it: `La doccia è rotta.`, pl: `Prysznic jest zepsuty.`, ipa: `/la dot-cza e rot-ta/`},{it: `Mi serve un asciugamano.`, pl: `Potrzebuję ręcznika.`, ipa: `/mi ser-we un a-szu-ga-ma-no/`},{it: `La camera non è pulita.`, pl: `Pokój nie jest czysty.`, ipa: `/la ka-me-ra non e pu-li-ta/`},{it: `C'è troppo rumore.`, pl: `Jest za dużo hałasu.`, ipa: `/cze trop-po ru-mo-re/`}], grammar: `C'è oznacza „jest/znajduje się” i jest bardzo częste w praktycznych sytuacjach. Non przed czasownikiem tworzy przeczenie: non funziona, czyli „nie działa”. Mi serve znaczy „potrzebuję” w sensie „jest mi potrzebny”.`, practice: [`Powiedz, że jest problem.`,`Zgłoś, że klimatyzacja nie działa.`,`Poproś o ręcznik.`,`Powiedz, że pokój nie jest czysty.`,`Powiedz, że jest za dużo hałasu.`]},{day: 13, title: `W restauracji`, title_native: `Al ristorante`, focus: `Kolacja w restauracji w Rzymie lub Bolonii ma swój rytm: stolik, menu, zamówienie i rachunek. Nauczysz się prowadzić prostą rozmowę z kelnerem.`, vocab: [{it: `ristorante`, pl: `restauracja`, ipa: `/ris-to-ran-te/`},{it: `cameriere`, pl: `kelner`, ipa: `/ka-me-rie-re/`},{it: `tavolo`, pl: `stolik`, ipa: `/ta-wo-lo/`},{it: `antipasto`, pl: `przystawka`, ipa: `/an-ti-pas-to/`},{it: `primo`, pl: `pierwsze danie`, ipa: `/pri-mo/`},{it: `secondo`, pl: `drugie danie`, ipa: `/se-kon-do/`},{it: `dolce`, pl: `deser`, ipa: `/dol-cze/`},{it: `conto`, pl: `rachunek`, ipa: `/kon-to/`},{it: `coperto`, pl: `opłata za nakrycie`, ipa: `/ko-per-to/`},{it: `mancia`, pl: `napiwek`, ipa: `/man-cza/`}], phrases: [{it: `Un tavolo per due, per favore.`, pl: `Stolik dla dwóch osób, proszę.`, ipa: `/un ta-wo-lo per du-e per fa-wo-re/`},{it: `Abbiamo una prenotazione.`, pl: `Mamy rezerwację.`, ipa: `/ab-bia-mo u-na pre-no-ta-cjo-ne/`},{it: `Vorrei ordinare.`, pl: `Chciałbym/chciałabym zamówić.`, ipa: `/wor-rej or-di-na-re/`},{it: `Prendo questo.`, pl: `Wezmę to.`, ipa: `/pren-do kue-sto/`},{it: `Era tutto buonissimo.`, pl: `Wszystko było przepyszne.`, ipa: `/e-ra tut-to bu-o-nis-si-mo/`},{it: `Possiamo avere il conto?`, pl: `Czy możemy dostać rachunek?`, ipa: `/pos-sia-mo a-we-re il kon-to/`}], grammar: `Włoskie menu często dzieli się na antipasti, primi, secondi i dolci. Prendo znaczy „biorę/wezmę” i jest bardzo naturalne przy zamawianiu. Possiamo avere...? to uprzejme „czy możemy dostać...?”.`, practice: [`Poproś o stolik dla dwóch osób.`,`Powiedz, że macie rezerwację.`,`Powiedz, że chcesz zamówić.`,`Wskaż danie i powiedz „wezmę to”.`,`Poproś o rachunek dla stolika.`]},{day: 14, title: `Dieta i alergie`, title_native: `Dieta e allergie`, focus: `Podczas jedzenia w obcym kraju ważne jest jasne mówienie o alergiach i ograniczeniach. Nauczysz się zwrotów przydatnych w restauracji w każdym włoskim mieście.`, vocab: [{it: `allergia`, pl: `alergia`, ipa: `/al-ler-dżi-a/`},{it: `senza glutine`, pl: `bez glutenu`, ipa: `/sen-dza glu-ti-ne/`},{it: `vegetariano`, pl: `wegetariański`, ipa: `/we-dże-ta-ria-no/`},{it: `vegano`, pl: `wegański`, ipa: `/we-ga-no/`},{it: `latte`, pl: `mleko`, ipa: `/lat-te/`},{it: `uova`, pl: `jajka`, ipa: `/uo-wa/`},{it: `noci`, pl: `orzechy`, ipa: `/no-czi/`},{it: `frutti di mare`, pl: `owoce morza`, ipa: `/frut-ti di ma-re/`},{it: `piccante`, pl: `pikantny`, ipa: `/pik-kan-te/`},{it: `ingredienti`, pl: `składniki`, ipa: `/in-gre-dien-ti/`}], phrases: [{it: `Sono allergico alle noci.`, pl: `Jestem uczulony na orzechy.`, ipa: `/so-no al-ler-dżi-ko al-le no-czi/`},{it: `Sono allergica alle noci.`, pl: `Jestem uczulona na orzechy.`, ipa: `/so-no al-ler-dżi-ka al-le no-czi/`},{it: `Avete piatti vegetariani?`, pl: `Czy macie dania wegetariańskie?`, ipa: `/a-we-te piat-ti we-dże-ta-ria-ni/`},{it: `È senza glutine?`, pl: `Czy to jest bez glutenu?`, ipa: `/e sen-dza glu-ti-ne/`},{it: `Ci sono frutti di mare?`, pl: `Czy są tu owoce morza?`, ipa: `/czi so-no frut-ti di ma-re/`},{it: `Non posso mangiare latte.`, pl: `Nie mogę jeść mleka/nabiału.`, ipa: `/non pos-so man-dża-re lat-te/`}], grammar: `Przy alergiach forma przymiotnika zależy od osoby: allergico mówi mężczyzna, allergica kobieta. Ci sono oznacza „są/znajdują się”, więc ci sono noci? to „czy są orzechy?”. Przy ograniczeniach bardzo praktyczne jest non posso mangiare, czyli „nie mogę jeść”.`, practice: [`Powiedz, że jesteś uczulony/uczulona na orzechy.`,`Zapytaj, czy danie jest bez glutenu.`,`Zapytaj, czy restauracja ma dania wegetariańskie.`,`Powiedz, że nie możesz jeść nabiału.`,`Zapytaj, czy w daniu są owoce morza.`]},{day: 15, title: `Zakupy spożywcze i targ`, title_native: `Spesa e mercato`, focus: `Na targu w Palermo, Bolonii lub Florencji możesz kupić owoce, ser i lokalne produkty. Nauczysz się pytać o ilość, cenę i świeżość.`, vocab: [{it: `mercato`, pl: `targ`, ipa: `/mer-ka-to/`},{it: `frutta`, pl: `owoce`, ipa: `/frut-ta/`},{it: `verdura`, pl: `warzywa`, ipa: `/wer-du-ra/`},{it: `pomodoro`, pl: `pomidor`, ipa: `/po-mo-do-ro/`},{it: `mela`, pl: `jabłko`, ipa: `/me-la/`},{it: `arancia`, pl: `pomarańcza`, ipa: `/a-ran-cza/`},{it: `prosciutto`, pl: `szynka`, ipa: `/pro-szut-to/`},{it: `etto`, pl: `100 gramów`, ipa: `/et-to/`},{it: `chilo`, pl: `kilogram`, ipa: `/ki-lo/`},{it: `fresco`, pl: `świeży`, ipa: `/fres-ko/`}], phrases: [{it: `Quanto costa al chilo?`, pl: `Ile kosztuje za kilogram?`, ipa: `/kuan-to kos-ta al ki-lo/`},{it: `Vorrei mezzo chilo di pomodori.`, pl: `Poproszę pół kilo pomidorów.`, ipa: `/wor-rej med-dzo ki-lo di po-mo-do-ri/`},{it: `Due etti di prosciutto, per favore.`, pl: `Dwie setki szynki, proszę.`, ipa: `/du-e et-ti di pro-szut-to per fa-wo-re/`},{it: `È fresco?`, pl: `Czy to świeże?`, ipa: `/e fres-ko/`},{it: `Posso assaggiare?`, pl: `Czy mogę spróbować?`, ipa: `/pos-so as-sad-dża-re/`},{it: `Basta così, grazie.`, pl: `Wystarczy tak, dziękuję.`, ipa: `/bas-ta ko-zi gra-cje/`}], grammar: `We Włoszech na targu często używa się etto, czyli 100 gramów. Due etti to 200 gramów. Mezzo znaczy „pół”, więc mezzo chilo to pół kilograma. Basta così to naturalny sposób, by powiedzieć sprzedawcy „wystarczy”.`, practice: [`Zapytaj o cenę za kilogram.`,`Poproś o pół kilo pomidorów.`,`Poproś o 200 gramów szynki.`,`Zapytaj, czy produkt jest świeży.`,`Powiedz „wystarczy tak, dziękuję”.`]},{day: 16, title: `Sklepy i pamiątki`, title_native: `Negozi e souvenir`, focus: `W małych sklepach w Wenecji lub Rzymie przydaje się język zakupów. Nauczysz się pytać o rozmiar, kolor, cenę i możliwość płatności kartą.`, vocab: [{it: `negozio`, pl: `sklep`, ipa: `/ne-go-cjo/`},{it: `souvenir`, pl: `pamiątka`, ipa: `/su-we-nir/`},{it: `prezzo`, pl: `cena`, ipa: `/pret-tso/`},{it: `sconto`, pl: `zniżka`, ipa: `/skon-to/`},{it: `taglia`, pl: `rozmiar`, ipa: `/ta-lia/`},{it: `colore`, pl: `kolor`, ipa: `/ko-lo-re/`},{it: `rosso`, pl: `czerwony`, ipa: `/ros-so/`},{it: `blu`, pl: `niebieski`, ipa: `/blu/`},{it: `bianco`, pl: `biały`, ipa: `/bian-ko/`},{it: `nero`, pl: `czarny`, ipa: `/ne-ro/`}], phrases: [{it: `Quanto costa questo?`, pl: `Ile to kosztuje?`, ipa: `/kuan-to kos-ta kue-sto/`},{it: `Avete una taglia più grande?`, pl: `Czy macie większy rozmiar?`, ipa: `/a-we-te u-na ta-lia piu gran-de/`},{it: `Avete questo in blu?`, pl: `Czy macie to w kolorze niebieskim?`, ipa: `/a-we-te kue-sto in blu/`},{it: `Posso pagare con carta?`, pl: `Czy mogę zapłacić kartą?`, ipa: `/pos-so pa-ga-re kon kar-ta/`},{it: `C'è uno sconto?`, pl: `Czy jest zniżka?`, ipa: `/cze u-no skon-to/`},{it: `Lo prendo.`, pl: `Wezmę to.`, ipa: `/lo pren-do/`}], grammar: `Questo oznacza „to” albo „ten”, gdy wskazujesz rzecz blisko siebie. Più grande znaczy „większy”, a più piccolo „mniejszy”. Con carta oznacza „kartą”, dosłownie „z kartą”.`, practice: [`Zapytaj, ile kosztuje wskazana rzecz.`,`Zapytaj o większy rozmiar.`,`Zapytaj, czy jest inny kolor.`,`Zapytaj, czy możesz zapłacić kartą.`,`Powiedz sprzedawcy „wezmę to”.`]},{day: 17, title: `Godziny i plan dnia`, title_native: `Ore e programma della giornata`, focus: `Zwiedzając muzea w Rzymie lub planując pociąg do Pizy, musisz rozumieć godziny. Nauczysz się pytać o otwarcie, zamknięcie i umawiać prosty plan.`, vocab: [{it: `ora`, pl: `godzina`, ipa: `/o-ra/`},{it: `oggi`, pl: `dzisiaj`, ipa: `/od-dżi/`},{it: `domani`, pl: `jutro`, ipa: `/do-ma-ni/`},{it: `mattina`, pl: `poranek`, ipa: `/mat-ti-na/`},{it: `pomeriggio`, pl: `popołudnie`, ipa: `/po-me-rid-dżo/`},{it: `sera`, pl: `wieczór`, ipa: `/se-ra/`},{it: `aperto`, pl: `otwarte`, ipa: `/a-per-to/`},{it: `chiuso`, pl: `zamknięte`, ipa: `/kiu-zo/`},{it: `presto`, pl: `wcześnie`, ipa: `/pres-to/`},{it: `tardi`, pl: `późno`, ipa: `/tar-di/`}], phrases: [{it: `Che ora è?`, pl: `Która godzina?`, ipa: `/ke o-ra e/`},{it: `È aperto oggi?`, pl: `Czy dzisiaj jest otwarte?`, ipa: `/e a-per-to od-dżi/`},{it: `A che ora chiude?`, pl: `O której zamyka?`, ipa: `/a ke o-ra kiu-de/`},{it: `A che ora apre?`, pl: `O której otwiera?`, ipa: `/a ke o-ra a-pre/`},{it: `Ci vediamo domani mattina.`, pl: `Widzimy się jutro rano.`, ipa: `/czi we-dia-mo do-ma-ni mat-ti-na/`},{it: `È troppo tardi.`, pl: `Jest za późno.`, ipa: `/e trop-po tar-di/`}], grammar: `A che ora...? znaczy „o której godzinie...?”. Apre i chiude to „otwiera” i „zamyka”. Oggi i domani warto znać od razu, bo pojawiają się przy rezerwacjach, biletach i planach.`, practice: [`Zapytaj, która godzina.`,`Zapytaj, czy muzeum jest dziś otwarte.`,`Zapytaj, o której zamyka restauracja.`,`Powiedz „widzimy się jutro rano”.`,`Powiedz, że jest za późno.`]},{day: 18, title: `Dni tygodnia i rezerwacje`, title_native: `Giorni della settimana e prenotazioni`, focus: `Rezerwując stolik w Wenecji lub wejście do galerii we Florencji, musisz podać dzień i godzinę. Nauczysz się nazw dni oraz prostych rezerwacji.`, vocab: [{it: `lunedì`, pl: `poniedziałek`, ipa: `/lu-ne-di/`},{it: `martedì`, pl: `wtorek`, ipa: `/mar-te-di/`},{it: `mercoledì`, pl: `środa`, ipa: `/mer-ko-le-di/`},{it: `giovedì`, pl: `czwartek`, ipa: `/dżo-we-di/`},{it: `venerdì`, pl: `piątek`, ipa: `/we-ner-di/`},{it: `sabato`, pl: `sobota`, ipa: `/sa-ba-to/`},{it: `domenica`, pl: `niedziela`, ipa: `/do-me-ni-ka/`},{it: `prenotare`, pl: `rezerwować`, ipa: `/pre-no-ta-re/`},{it: `disponibile`, pl: `dostępny`, ipa: `/dis-po-ni-bi-le/`},{it: `occupato`, pl: `zajęty`, ipa: `/ok-ku-pa-to/`}], phrases: [{it: `Vorrei prenotare per venerdì.`, pl: `Chciałbym/chciałabym zarezerwować na piątek.`, ipa: `/wor-rej pre-no-ta-re per we-ner-di/`},{it: `Avete posto per due?`, pl: `Czy macie miejsce dla dwóch osób?`, ipa: `/a-we-te pos-to per du-e/`},{it: `Alle otto di sera.`, pl: `O ósmej wieczorem.`, ipa: `/al-le ot-to di se-ra/`},{it: `È disponibile sabato?`, pl: `Czy jest dostępne w sobotę?`, ipa: `/e dis-po-ni-bi-le sa-ba-to/`},{it: `Siamo in quattro.`, pl: `Jest nas czworo.`, ipa: `/sia-mo in kuat-tro/`},{it: `Devo cancellare la prenotazione.`, pl: `Muszę anulować rezerwację.`, ipa: `/de-wo kan-czel-la-re la pre-no-ta-cjo-ne/`}], grammar: `Dni tygodnia po włosku zwykle pisze się małą literą. Per venerdì oznacza „na piątek”. Siamo in quattro to naturalny sposób powiedzenia „jest nas czworo”, szczególnie przy stoliku lub wejściu do atrakcji.`, practice: [`Powiedz wszystkie dni tygodnia po włosku.`,`Zarezerwuj stolik na piątek.`,`Powiedz, że jest was czworo.`,`Zapytaj, czy jest miejsce dla dwóch osób.`,`Powiedz, że musisz anulować rezerwację.`]},{day: 19, title: `Zwiedzanie miasta`, title_native: `Visitare la città`, focus: `We Florencji, Rzymie i Weronie zwiedzanie wymaga słów związanych z muzeami, biletami i zabytkami. Nauczysz się pytać o wejście, godziny i rekomendacje.`, vocab: [{it: `museo`, pl: `muzeum`, ipa: `/mu-ze-o/`},{it: `chiesa`, pl: `kościół`, ipa: `/kie-za/`},{it: `castello`, pl: `zamek`, ipa: `/kas-tel-lo/`},{it: `ponte`, pl: `most`, ipa: `/pon-te/`},{it: `fontana`, pl: `fontanna`, ipa: `/fon-ta-na/`},{it: `biglietteria`, pl: `kasa biletowa`, ipa: `/bi-liet-te-ria/`},{it: `ingresso`, pl: `wejście`, ipa: `/in-gres-so/`},{it: `uscita`, pl: `wyjście`, ipa: `/u-szi-ta/`},{it: `guida`, pl: `przewodnik`, ipa: `/gui-da/`},{it: `visita`, pl: `zwiedzanie`, ipa: `/wi-zi-ta/`}], phrases: [{it: `Dov'è l'ingresso?`, pl: `Gdzie jest wejście?`, ipa: `/do-we lin-gres-so/`},{it: `Quanto costa l'ingresso?`, pl: `Ile kosztuje wejście?`, ipa: `/kuan-to kos-ta lin-gres-so/`},{it: `C'è una visita guidata?`, pl: `Czy jest zwiedzanie z przewodnikiem?`, ipa: `/cze u-na wi-zi-ta gui-da-ta/`},{it: `Posso fare una foto?`, pl: `Czy mogę zrobić zdjęcie?`, ipa: `/pos-so fa-re u-na fo-to/`},{it: `Quale museo consiglia?`, pl: `Które muzeum pan/pani poleca?`, ipa: `/kua-le mu-ze-o kon-si-lia/`},{it: `Dov'è l'uscita?`, pl: `Gdzie jest wyjście?`, ipa: `/do-we lu-szi-ta/`}], grammar: `L'ingresso i l'uscita mają apostrof, bo rodzajnik skraca się przed samogłoską. Fare una foto znaczy „zrobić zdjęcie”. C'è una...? to wygodny wzór pytania „czy jest jakaś...?”.`, practice: [`Zapytaj, gdzie jest wejście.`,`Zapytaj, ile kosztuje wejście.`,`Zapytaj o zwiedzanie z przewodnikiem.`,`Zapytaj, czy możesz zrobić zdjęcie.`,`Zapytaj miejscową osobę, które muzeum poleca.`]},{day: 20, title: `Telefon, internet i aplikacje`, title_native: `Telefono, internet e app`, focus: `Podczas podróży po Włoszech często potrzebujesz Wi-Fi, ładowarki lub karty SIM. Nauczysz się pytać o internet, hasło i problemy z telefonem.`, vocab: [{it: `telefono`, pl: `telefon`, ipa: `/te-le-fo-no/`},{it: `internet`, pl: `internet`, ipa: `/in-ter-net/`},{it: `Wi-Fi`, pl: `Wi-Fi`, ipa: `/wi-faj/`},{it: `password`, pl: `hasło`, ipa: `/pas-word/`},{it: `caricatore`, pl: `ładowarka`, ipa: `/ka-ri-ka-to-re/`},{it: `batteria`, pl: `bateria`, ipa: `/bat-te-ria/`},{it: `presa`, pl: `gniazdko`, ipa: `/pre-za/`},{it: `scheda SIM`, pl: `karta SIM`, ipa: `/ske-da sim/`},{it: `app`, pl: `aplikacja`, ipa: `/ap/`},{it: `funzionare`, pl: `działać`, ipa: `/fun-cjo-na-re/`}], phrases: [{it: `Avete il Wi-Fi?`, pl: `Czy macie Wi-Fi?`, ipa: `/a-we-te il wi-faj/`},{it: `Qual è la password?`, pl: `Jakie jest hasło?`, ipa: `/kual e la pas-word/`},{it: `Il mio telefono non funziona.`, pl: `Mój telefon nie działa.`, ipa: `/il mio te-le-fo-no non fun-cjo-na/`},{it: `Dov'è una presa?`, pl: `Gdzie jest gniazdko?`, ipa: `/do-we u-na pre-za/`},{it: `Mi serve un caricatore.`, pl: `Potrzebuję ładowarki.`, ipa: `/mi ser-we un ka-ri-ka-to-re/`},{it: `Posso usare questa app?`, pl: `Czy mogę użyć tej aplikacji?`, ipa: `/pos-so u-za-re kue-sta ap/`}], grammar: `Mi serve działa z rzeczami, których potrzebujesz: mi serve un caricatore, mi serve una presa. Qual è oznacza „jakie/jaki jest”. Włoskie non funziona przyda się nie tylko przy telefonie, ale też przy klimatyzacji, karcie i automacie biletowym.`, practice: [`Zapytaj, czy kawiarnia ma Wi-Fi.`,`Zapytaj o hasło.`,`Powiedz, że twój telefon nie działa.`,`Zapytaj, gdzie jest gniazdko.`,`Powiedz, że potrzebujesz ładowarki.`]},{day: 21, title: `Zdrowie i apteka`, title_native: `Salute e farmacia`, focus: `W aptece w Rzymie lub Mediolanie musisz jasno powiedzieć, co ci dolega. Nauczysz się opisywać podstawowe objawy i prosić o pomoc farmaceutę.`, vocab: [{it: `farmacia`, pl: `apteka`, ipa: `/far-ma-czi-a/`},{it: `medicina`, pl: `lekarstwo`, ipa: `/me-di-czi-na/`},{it: `dolore`, pl: `ból`, ipa: `/do-lo-re/`},{it: `testa`, pl: `głowa`, ipa: `/tes-ta/`},{it: `stomaco`, pl: `żołądek`, ipa: `/sto-ma-ko/`},{it: `febbre`, pl: `gorączka`, ipa: `/feb-bre/`},{it: `tosse`, pl: `kaszel`, ipa: `/tos-se/`},{it: `raffreddore`, pl: `przeziębienie`, ipa: `/raf-fred-do-re/`},{it: `cerotto`, pl: `plaster`, ipa: `/cze-rot-to/`},{it: `dottore`, pl: `lekarz`, ipa: `/dot-to-re/`}], phrases: [{it: `Ho mal di testa.`, pl: `Boli mnie głowa.`, ipa: `/o mal di tes-ta/`},{it: `Ho mal di stomaco.`, pl: `Boli mnie żołądek.`, ipa: `/o mal di sto-ma-ko/`},{it: `Ho la febbre.`, pl: `Mam gorączkę.`, ipa: `/o la feb-bre/`},{it: `Mi serve una medicina.`, pl: `Potrzebuję lekarstwa.`, ipa: `/mi ser-we u-na me-di-czi-na/`},{it: `Dov'è la farmacia più vicina?`, pl: `Gdzie jest najbliższa apteka?`, ipa: `/do-we la far-ma-czi-a piu wi-czi-na/`},{it: `Devo vedere un dottore.`, pl: `Muszę zobaczyć się z lekarzem.`, ipa: `/de-wo we-de-re un dot-to-re/`}], grammar: `Ho znaczy „mam” i występuje w wielu zwrotach zdrowotnych: ho la febbre, ho mal di testa. Mal di oznacza „ból czegoś”, np. mal di stomaco. Più vicina znaczy „najbliższa” dla rzeczownika żeńskiego, jak farmacia.`, practice: [`Powiedz, że boli cię głowa.`,`Powiedz, że masz gorączkę.`,`Zapytaj o najbliższą aptekę.`,`Powiedz, że potrzebujesz lekarstwa.`,`Powiedz, że musisz zobaczyć się z lekarzem.`]},{day: 22, title: `Nagłe sytuacje`, title_native: `Emergenze`, focus: `W nagłych sytuacjach liczą się krótkie, jasne komunikaty. Nauczysz się prosić o pomoc, wzywać policję lub karetkę i opisywać problem.`, vocab: [{it: `emergenza`, pl: `nagły wypadek`, ipa: `/e-mer-dżen-dza/`},{it: `aiuto`, pl: `pomoc`, ipa: `/a-ju-to/`},{it: `polizia`, pl: `policja`, ipa: `/po-li-cji-a/`},{it: `ambulanza`, pl: `karetka`, ipa: `/am-bu-lan-dza/`},{it: `ospedale`, pl: `szpital`, ipa: `/os-pe-da-le/`},{it: `incidente`, pl: `wypadek`, ipa: `/in-czi-den-te/`},{it: `furto`, pl: `kradzież`, ipa: `/fur-to/`},{it: `pericolo`, pl: `niebezpieczeństwo`, ipa: `/pe-ri-ko-lo/`},{it: `subito`, pl: `natychmiast`, ipa: `/su-bi-to/`},{it: `indirizzo`, pl: `adres`, ipa: `/in-di-rit-tso/`}], phrases: [{it: `Aiuto!`, pl: `Pomocy!`, ipa: `/a-ju-to/`},{it: `Chiamate la polizia!`, pl: `Zadzwońcie po policję!`, ipa: `/kia-ma-te la po-li-cji-a/`},{it: `Mi serve un'ambulanza.`, pl: `Potrzebuję karetki.`, ipa: `/mi ser-we un am-bu-lan-dza/`},{it: `C'è stato un incidente.`, pl: `Był wypadek.`, ipa: `/cze sta-to un in-czi-den-te/`},{it: `Dov'è l'ospedale?`, pl: `Gdzie jest szpital?`, ipa: `/do-we los-pe-da-le/`},{it: `Ho perso il passaporto.`, pl: `Zgubiłem/zgubiłam paszport.`, ipa: `/o per-so il pas-sa-por-to/`}], grammar: `Tryb rozkazujący w liczbie mnogiej, jak chiamate, może znaczyć „zadzwońcie”. W nagłej sytuacji nie martw się elegancją — krótkie zdania są najlepsze. Ho perso znaczy „zgubiłem/zgubiłam” i przyda się przy dokumentach lub telefonie.`, practice: [`Krzyknij po włosku „pomocy!”.`,`Powiedz, że potrzebujesz karetki.`,`Poproś, żeby ktoś zadzwonił po policję.`,`Powiedz, że był wypadek.`,`Powiedz, że zgubiłeś lub zgubiłaś paszport.`]},{day: 23, title: `Wynajem i mieszkanie`, title_native: `Affitto e alloggio`, focus: `Jeśli zatrzymujesz się w apartamencie w Rzymie, Bari lub Palermo, potrzebujesz słów o kluczach, wejściu i zasadach domu. Nauczysz się rozmawiać z gospodarzem.`, vocab: [{it: `appartamento`, pl: `apartament`, ipa: `/ap-par-ta-men-to/`},{it: `affitto`, pl: `wynajem`, ipa: `/af-fit-to/`},{it: `host`, pl: `gospodarz`, ipa: `/host/`},{it: `porta`, pl: `drzwi`, ipa: `/por-ta/`},{it: `codice`, pl: `kod`, ipa: `/ko-di-cze/`},{it: `chiave`, pl: `klucz`, ipa: `/kia-we/`},{it: `cucina`, pl: `kuchnia`, ipa: `/ku-czi-na/`},{it: `bagno`, pl: `łazienka`, ipa: `/ba-nio/`},{it: `lavatrice`, pl: `pralka`, ipa: `/la-wa-tri-cze/`},{it: `regole`, pl: `zasady`, ipa: `/re-go-le/`}], phrases: [{it: `Dov'è la chiave?`, pl: `Gdzie jest klucz?`, ipa: `/do-we la kia-we/`},{it: `Qual è il codice della porta?`, pl: `Jaki jest kod do drzwi?`, ipa: `/kual e il ko-di-cze del-la por-ta/`},{it: `Posso usare la cucina?`, pl: `Czy mogę używać kuchni?`, ipa: `/pos-so u-za-re la ku-czi-na/`},{it: `La lavatrice funziona?`, pl: `Czy pralka działa?`, ipa: `/la la-wa-tri-cze fun-cjo-na/`},{it: `A che ora è il check-out?`, pl: `O której jest wymeldowanie?`, ipa: `/a ke o-ra e il czek-aut/`},{it: `Ci sono regole importanti?`, pl: `Czy są jakieś ważne zasady?`, ipa: `/czi so-no re-go-le im-por-tan-ti/`}], grammar: `Della znaczy „od/do” w połączeniu z rzeczownikiem żeńskim: codice della porta to „kod do drzwi”. Posso usare...? znaczy „czy mogę używać...?”. Ci sono regole...? jest naturalnym pytaniem o zasady w mieszkaniu.`, practice: [`Zapytaj, gdzie jest klucz.`,`Zapytaj o kod do drzwi.`,`Zapytaj, czy możesz używać kuchni.`,`Zapytaj, czy pralka działa.`,`Zapytaj o godzinę wymeldowania.`]},{day: 24, title: `Pogoda i ubrania`, title_native: `Meteo e vestiti`, focus: `Pogoda w Mediolanie, Neapolu i na Sycylii może być bardzo różna. Nauczysz się mówić o deszczu, upale i podstawowych ubraniach.`, vocab: [{it: `tempo`, pl: `pogoda; czas`, ipa: `/tem-po/`},{it: `sole`, pl: `słońce`, ipa: `/so-le/`},{it: `pioggia`, pl: `deszcz`, ipa: `/piod-dża/`},{it: `vento`, pl: `wiatr`, ipa: `/wen-to/`},{it: `caldo`, pl: `gorąco`, ipa: `/kal-do/`},{it: `freddo`, pl: `zimno`, ipa: `/fred-do/`},{it: `giacca`, pl: `kurtka`, ipa: `/dżak-ka/`},{it: `scarpe`, pl: `buty`, ipa: `/skar-pe/`},{it: `ombrello`, pl: `parasol`, ipa: `/om-brel-lo/`},{it: `vestiti`, pl: `ubrania`, ipa: `/we-sti-ti/`}], phrases: [{it: `Che tempo fa?`, pl: `Jaka jest pogoda?`, ipa: `/ke tem-po fa/`},{it: `Fa caldo.`, pl: `Jest gorąco.`, ipa: `/fa kal-do/`},{it: `Fa freddo.`, pl: `Jest zimno.`, ipa: `/fa fred-do/`},{it: `Piove.`, pl: `Pada deszcz.`, ipa: `/pio-we/`},{it: `Mi serve un ombrello.`, pl: `Potrzebuję parasola.`, ipa: `/mi ser-we un om-brel-lo/`},{it: `Devo comprare una giacca.`, pl: `Muszę kupić kurtkę.`, ipa: `/de-wo kom-pra-re u-na dżak-ka/`}], grammar: `Do opisu pogody często używa się fa: fa caldo, fa freddo. Piove to jedno słowo oznaczające „pada deszcz”. Tempo może znaczyć zarówno „czas”, jak i „pogoda”, więc kontekst jest ważny.`, practice: [`Zapytaj, jaka jest pogoda.`,`Powiedz, że jest gorąco.`,`Powiedz, że pada deszcz.`,`Powiedz, że potrzebujesz parasola.`,`Powiedz, że musisz kupić kurtkę.`]},{day: 25, title: `Rozmowy towarzyskie`, title_native: `Conversazioni sociali`, focus: `W hostelu, barze lub na wycieczce w Toskanii możesz poznać lokalnych mieszkańców i innych podróżnych. Nauczysz się prowadzić prostą, miłą rozmowę.`, vocab: [{it: `amico`, pl: `przyjaciel`, ipa: `/a-mi-ko/`},{it: `amica`, pl: `przyjaciółka`, ipa: `/a-mi-ka/`},{it: `viaggio`, pl: `podróż`, ipa: `/wiad-dżo/`},{it: `vacanza`, pl: `wakacje`, ipa: `/wa-kan-dza/`},{it: `lavoro`, pl: `praca`, ipa: `/la-wo-ro/`},{it: `famiglia`, pl: `rodzina`, ipa: `/fa-mi-lia/`},{it: `musica`, pl: `muzyka`, ipa: `/mu-zi-ka/`},{it: `città`, pl: `miasto`, ipa: `/czit-ta/`},{it: `bello`, pl: `piękny; ładny`, ipa: `/bel-lo/`},{it: `interessante`, pl: `interesujący`, ipa: `/in-te-res-san-te/`}], phrases: [{it: `Sei in vacanza?`, pl: `Jesteś na wakacjach?`, ipa: `/sej in wa-kan-dza/`},{it: `Sono qui per lavoro.`, pl: `Jestem tu w pracy.`, ipa: `/so-no kui per la-wo-ro/`},{it: `Questa città è bellissima.`, pl: `To miasto jest przepiękne.`, ipa: `/kue-sta czit-ta e bel-lis-si-ma/`},{it: `Ti piace la musica italiana?`, pl: `Lubisz włoską muzykę?`, ipa: `/ti pia-cze la mu-zi-ka i-ta-lia-na/`},{it: `Da quanto tempo sei qui?`, pl: `Jak długo tu jesteś?`, ipa: `/da kuan-to tem-po sej kui/`},{it: `È stato un piacere.`, pl: `To była przyjemność.`, ipa: `/e sta-to un pia-cze-re/`}], grammar: `Sei oznacza „jesteś” w rozmowie nieformalnej. Bellissima to mocniejsza forma od bella i znaczy „przepiękna”. Da quanto tempo...? pyta o czas trwania, np. jak długo ktoś jest w mieście.`, practice: [`Zapytaj kogoś, czy jest na wakacjach.`,`Powiedz, że jesteś tu w pracy.`,`Powiedz, że miasto jest przepiękne.`,`Zapytaj, czy ktoś lubi włoską muzykę.`,`Zakończ rozmowę zwrotem „to była przyjemność”.`]},{day: 26, title: `Opinie i emocje`, title_native: `Opinioni ed emozioni`, focus: `Podczas podróży często chcesz powiedzieć, że coś ci się podoba, jest piękne albo jesteś zmęczony. Nauczysz się wyrażać proste opinie i uczucia.`, vocab: [{it: `felice`, pl: `szczęśliwy`, ipa: `/fe-li-cze/`},{it: `stanco`, pl: `zmęczony`, ipa: `/stan-ko/`},{it: `stanca`, pl: `zmęczona`, ipa: `/stan-ka/`},{it: `contento`, pl: `zadowolony`, ipa: `/kon-ten-to/`},{it: `contenta`, pl: `zadowolona`, ipa: `/kon-ten-ta/`},{it: `bello`, pl: `piękny`, ipa: `/bel-lo/`},{it: `brutto`, pl: `brzydki; zły`, ipa: `/brut-to/`},{it: `facile`, pl: `łatwy`, ipa: `/fa-czi-le/`},{it: `difficile`, pl: `trudny`, ipa: `/dif-fi-czi-le/`},{it: `preferito`, pl: `ulubiony`, ipa: `/pre-fe-ri-to/`}], phrases: [{it: `Mi piace molto.`, pl: `Bardzo mi się podoba.`, ipa: `/mi pia-cze mol-to/`},{it: `Non mi piace.`, pl: `Nie podoba mi się.`, ipa: `/non mi pia-cze/`},{it: `Sono stanco.`, pl: `Jestem zmęczony.`, ipa: `/so-no stan-ko/`},{it: `Sono stanca.`, pl: `Jestem zmęczona.`, ipa: `/so-no stan-ka/`},{it: `È facile.`, pl: `To jest łatwe.`, ipa: `/e fa-czi-le/`},{it: `Qual è il tuo posto preferito?`, pl: `Jakie jest twoje ulubione miejsce?`, ipa: `/kual e il tuo pos-to pre-fe-ri-to/`}], grammar: `Przymiotniki często zmieniają końcówkę zależnie od rodzaju: stanco mówi mężczyzna, stanca mówi kobieta. Mi piace molto to bardzo przydatny zwrot do jedzenia, miasta, muzyki i miejsc. Qual è il tuo...? pozwala pytać o czyjeś preferencje.`, practice: [`Powiedz, że coś bardzo ci się podoba.`,`Powiedz, że coś ci się nie podoba.`,`Powiedz „jestem zmęczony” albo „jestem zmęczona”.`,`Powiedz, że coś jest łatwe.`,`Zapytaj kogoś o jego ulubione miejsce.`]},{day: 27, title: `Plany i zaproszenia`, title_native: `Piani e inviti`, focus: `Gdy poznasz kogoś w Rzymie lub Florencji, możesz chcieć zaproponować kawę, spacer albo wspólne zwiedzanie. Nauczysz się prostych zaproszeń i odpowiedzi.`, vocab: [{it: `piano`, pl: `plan`, ipa: `/pia-no/`},{it: `invito`, pl: `zaproszenie`, ipa: `/in-wi-to/`},{it: `cena`, pl: `kolacja`, ipa: `/cze-na/`},{it: `pranzo`, pl: `lunch; obiad`, ipa: `/pran-dzo/`},{it: `passeggiata`, pl: `spacer`, ipa: `/pas-sed-dża-ta/`},{it: `domani`, pl: `jutro`, ipa: `/do-ma-ni/`},{it: `stasera`, pl: `dziś wieczorem`, ipa: `/sta-se-ra/`},{it: `insieme`, pl: `razem`, ipa: `/in-sie-me/`},{it: `libero`, pl: `wolny`, ipa: `/li-be-ro/`},{it: `occupato`, pl: `zajęty`, ipa: `/ok-ku-pa-to/`}], phrases: [{it: `Hai programmi per stasera?`, pl: `Masz plany na dziś wieczór?`, ipa: `/aj pro-gram-mi per sta-se-ra/`},{it: `Vuoi prendere un caffè?`, pl: `Chcesz pójść na kawę?`, ipa: `/wu-oj pren-de-re un kaf-fe/`},{it: `Andiamo a cena insieme?`, pl: `Pójdziemy razem na kolację?`, ipa: `/an-dia-mo a cze-na in-sie-me/`},{it: `Sono libero domani.`, pl: `Jestem wolny jutro.`, ipa: `/so-no li-be-ro do-ma-ni/`},{it: `Mi dispiace, sono occupato.`, pl: `Przykro mi, jestem zajęty.`, ipa: `/mi dis-pia-cze so-no ok-ku-pa-to/`},{it: `Volentieri!`, pl: `Chętnie!`, ipa: `/wo-len-tie-ri/`}], grammar: `Vuoi...? znaczy „czy chcesz...?” i jest używane w rozmowie nieformalnej. Andiamo...? może znaczyć „chodźmy” lub „czy pójdziemy?”. Volentieri to bardzo naturalne „chętnie” w odpowiedzi na zaproszenie.`, practice: [`Zapytaj, czy ktoś ma plany na dziś wieczór.`,`Zaproponuj kawę.`,`Zaproponuj wspólną kolację.`,`Powiedz, że jesteś wolny jutro.`,`Uprzejmie odmów, mówiąc, że jesteś zajęty.`]},{day: 28, title: `Usługi i płatności`, title_native: `Servizi e pagamenti`, focus: `W podróży korzystasz z taksówki, pralni, salonu fryzjerskiego lub wypożyczalni. Nauczysz się mówić o usługach, cenie i płatności.`, vocab: [{it: `servizio`, pl: `usługa`, ipa: `/ser-wi-cjo/`},{it: `pagamento`, pl: `płatność`, ipa: `/pa-ga-men-to/`},{it: `contanti`, pl: `gotówka`, ipa: `/kon-tan-ti/`},{it: `carta`, pl: `karta`, ipa: `/kar-ta/`},{it: `ricevuta`, pl: `paragon; pokwitowanie`, ipa: `/ri-cze-wu-ta/`},{it: `taxi`, pl: `taksówka`, ipa: `/tak-si/`},{it: `lavanderia`, pl: `pralnia`, ipa: `/la-wan-de-ria/`},{it: `parrucchiere`, pl: `fryzjer`, ipa: `/par-ruk-kie-re/`},{it: `noleggio`, pl: `wynajem`, ipa: `/no-led-dżo/`},{it: `prezzo finale`, pl: `cena końcowa`, ipa: `/pret-tso fi-na-le/`}], phrases: [{it: `Quanto costa il servizio?`, pl: `Ile kosztuje usługa?`, ipa: `/kuan-to kos-ta il ser-wi-cjo/`},{it: `Posso pagare in contanti?`, pl: `Czy mogę zapłacić gotówką?`, ipa: `/pos-so pa-ga-re in kon-tan-ti/`},{it: `Posso pagare con carta?`, pl: `Czy mogę zapłacić kartą?`, ipa: `/pos-so pa-ga-re kon kar-ta/`},{it: `Mi serve una ricevuta.`, pl: `Potrzebuję paragonu.`, ipa: `/mi ser-we u-na ri-cze-wu-ta/`},{it: `Il prezzo finale è questo?`, pl: `Czy to jest cena końcowa?`, ipa: `/il pret-tso fi-na-le e kue-sto/`},{it: `Vorrei chiamare un taxi.`, pl: `Chciałbym/chciałabym zamówić taksówkę.`, ipa: `/wor-rej kia-ma-re un tak-si/`}], grammar: `Pagare in contanti oznacza „płacić gotówką”, a pagare con carta „płacić kartą”. Mi serve una ricevuta jest przydatne, gdy potrzebujesz potwierdzenia zakupu. Finale znaczy „końcowy”, jak w prezzo finale.`, practice: [`Zapytaj o koszt usługi.`,`Zapytaj, czy możesz zapłacić gotówką.`,`Poproś o paragon.`,`Zapytaj, czy to cena końcowa.`,`Powiedz, że chcesz zamówić taksówkę.`]},{day: 29, title: `Porównywanie i wybieranie`, title_native: `Confrontare e scegliere`, focus: `Przy wyborze restauracji, hotelu, pociągu lub pamiątki musisz porównać opcje. Nauczysz się mówić „lepszy”, „tańszy”, „bliżej” i „wolę”.`, vocab: [{it: `meglio`, pl: `lepiej`, ipa: `/me-lio/`},{it: `migliore`, pl: `lepszy`, ipa: `/mi-lio-re/`},{it: `peggiore`, pl: `gorszy`, ipa: `/ped-dżo-re/`},{it: `più economico`, pl: `tańszy`, ipa: `/piu e-ko-no-mi-ko/`},{it: `più caro`, pl: `droższy`, ipa: `/piu ka-ro/`},{it: `più vicino`, pl: `bliżej; bliższy`, ipa: `/piu wi-czi-no/`},{it: `più lontano`, pl: `dalej; dalszy`, ipa: `/piu lon-ta-no/`},{it: `veloce`, pl: `szybki`, ipa: `/we-lo-cze/`},{it: `lento`, pl: `wolny`, ipa: `/len-to/`},{it: `preferire`, pl: `woleć`, ipa: `/pre-fe-ri-re/`}], phrases: [{it: `Qual è meglio?`, pl: `Co jest lepsze?`, ipa: `/kual e me-lio/`},{it: `Questo è più economico.`, pl: `To jest tańsze.`, ipa: `/kue-sto e piu e-ko-no-mi-ko/`},{it: `Questo hotel è più vicino.`, pl: `Ten hotel jest bliżej.`, ipa: `/kue-sto o-tel e piu wi-czi-no/`},{it: `Preferisco questo.`, pl: `Wolę to.`, ipa: `/pre-fe-ris-ko kue-sto/`},{it: `Il treno è più veloce.`, pl: `Pociąg jest szybszy.`, ipa: `/il tre-no e piu we-lo-cze/`},{it: `È troppo caro.`, pl: `To jest za drogie.`, ipa: `/e trop-po ka-ro/`}], grammar: `Più przed przymiotnikiem tworzy porównanie: più caro, più veloce, più vicino. Preferisco znaczy „wolę” i świetnie działa z questo. Troppo oznacza „za bardzo/za”, więc troppo caro to „za drogie”.`, practice: [`Zapytaj, która opcja jest lepsza.`,`Powiedz, że coś jest tańsze.`,`Powiedz, że hotel jest bliżej.`,`Powiedz „wolę to”.`,`Powiedz, że pociąg jest szybszy.`]},{day: 30, title: `Pełny dzień podróży`, title_native: `Una giornata completa di viaggio`, focus: `Łączysz wszystko, czego nauczyłeś się do tej pory: hotel, transport, jedzenie, pytania i rozmowę. Wyobraź sobie cały dzień w Rzymie od śniadania po kolację.`, vocab: [{it: `giornata`, pl: `dzień jako przebieg wydarzeń`, ipa: `/dżor-na-ta/`},{it: `viaggiare`, pl: `podróżować`, ipa: `/wiad-dża-re/`},{it: `partire`, pl: `wyjeżdżać`, ipa: `/par-ti-re/`},{it: `arrivare`, pl: `przyjeżdżać`, ipa: `/ar-ri-wa-re/`},{it: `comprare`, pl: `kupować`, ipa: `/kom-pra-re/`},{it: `mangiare`, pl: `jeść`, ipa: `/man-dża-re/`},{it: `visitare`, pl: `zwiedzać`, ipa: `/wi-zi-ta-re/`},{it: `chiedere`, pl: `pytać`, ipa: `/kie-de-re/`},{it: `capire`, pl: `rozumieć`, ipa: `/ka-pi-re/`},{it: `ricordare`, pl: `pamiętać`, ipa: `/ri-kor-da-re/`}], phrases: [{it: `Oggi voglio visitare il centro.`, pl: `Dzisiaj chcę zwiedzić centrum.`, ipa: `/od-dżi wo-lio wi-zi-ta-re il czen-tro/`},{it: `Prima prendo un caffè.`, pl: `Najpierw wezmę kawę.`, ipa: `/pri-ma pren-do un kaf-fe/`},{it: `Poi compro un biglietto.`, pl: `Potem kupię bilet.`, ipa: `/poj kom-pro un bi-lie-tto/`},{it: `Non capisco, può ripetere?`, pl: `Nie rozumiem, czy może pan/pani powtórzyć?`, ipa: `/non ka-pis-ko puo ri-pe-te-re/`},{it: `Devo tornare in hotel.`, pl: `Muszę wrócić do hotelu.`, ipa: `/de-wo tor-na-re in o-tel/`},{it: `È stata una bella giornata.`, pl: `To był piękny dzień.`, ipa: `/e sta-ta u-na bel-la dżor-na-ta/`}], grammar: `Prima i poi pomagają budować prostą opowieść: najpierw, potem. Voglio znaczy „chcę”, ale w uprzejmych sytuacjach nadal lepiej używać vorrei. Non capisco, può ripetere? to jedno z najważniejszych zdań w podróży, bo pozwala spokojnie poprosić o powtórzenie.`, practice: [`Opisz po włosku plan: kawa, bilet, centrum.`,`Powiedz, że nie rozumiesz i poproś o powtórzenie.`,`Powiedz, że musisz wrócić do hotelu.`,`Powiedz, że dziś chcesz zwiedzić centrum.`,`Ułóż pięciozdaniową miniopowieść o dniu podróży po Rzymie.`]}];

var CONVERSATIONS_PL_IT = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś rano w małej kawiarni niedaleko dworca Termini w Rzymie. Chcesz szybko zamówić kawę i rogalik przy ladzie.`, lines: [{who: `them`, it: `Buongiorno, desidera?`, pl: `Dzień dobry, czego pan/pani sobie życzy?`},{who: `you`, it: `Buongiorno, un cappuccino e un cornetto, per favore.`, pl: `Dzień dobry, cappuccino i rogalik, proszę.`},{who: `them`, it: `Al banco o al tavolo?`, pl: `Przy ladzie czy przy stoliku?`},{who: `you`, it: `Al banco, grazie.`, pl: `Przy ladzie, dziękuję.`},{who: `them`, it: `Vuole zucchero?`, pl: `Czy chce pan/pani cukier?`},{who: `you`, it: `Sì, un po' di zucchero, per favore.`, pl: `Tak, trochę cukru, proszę.`},{who: `them`, it: `Altro?`, pl: `Coś jeszcze?`},{who: `you`, it: `Una bottiglia d'acqua naturale.`, pl: `Butelkę wody niegazowanej.`},{who: `them`, it: `Sono sei euro.`, pl: `To sześć euro.`},{who: `you`, it: `Posso pagare con carta?`, pl: `Czy mogę zapłacić kartą?`},{who: `them`, it: `Certo, prego.`, pl: `Oczywiście, proszę.`},{who: `you`, it: `Grazie mille, arrivederci.`, pl: `Bardzo dziękuję, do widzenia.`}]},{id: 2, title: `Zameldowanie w hotelu`, scene: `Przyjeżdżasz wieczorem do hotelu w centrum Florencji. Masz rezerwację i chcesz zapytać o śniadanie oraz możliwość zostawienia walizki następnego dnia.`, lines: [{who: `them`, it: `Buonasera, benvenuto in hotel.`, pl: `Dobry wieczór, witamy w hotelu.`},{who: `you`, it: `Buonasera, ho una prenotazione a nome Kowalski.`, pl: `Dobry wieczór, mam rezerwację na nazwisko Kowalski.`},{who: `them`, it: `Certo, posso avere un documento?`, pl: `Oczywiście, czy mogę prosić o dokument?`},{who: `you`, it: `Sì, ecco il passaporto.`, pl: `Tak, oto paszport.`},{who: `them`, it: `La sua camera è al terzo piano.`, pl: `Pana/pani pokój jest na trzecim piętrze.`},{who: `you`, it: `La colazione è inclusa?`, pl: `Czy śniadanie jest wliczone?`},{who: `them`, it: `Sì, dalle sette alle dieci.`, pl: `Tak, od siódmej do dziesiątej.`},{who: `you`, it: `A che ora è il check-out?`, pl: `O której jest wymeldowanie?`},{who: `them`, it: `Il check-out è alle undici.`, pl: `Wymeldowanie jest o jedenastej.`},{who: `you`, it: `Posso lasciare la valigia qui domani?`, pl: `Czy mogę zostawić tu walizkę jutro?`},{who: `them`, it: `Sì, certo, alla reception.`, pl: `Tak, oczywiście, w recepcji.`},{who: `you`, it: `Perfetto, grazie mille.`, pl: `Świetnie, bardzo dziękuję.`}]},{id: 3, title: `Pytanie o drogę`, scene: `Spacerujesz po Wenecji i próbujesz znaleźć most Rialto. Zatrzymujesz lokalną osobę i prosisz o wskazówki.`, lines: [{who: `you`, it: `Scusi, posso chiedere un'informazione?`, pl: `Przepraszam, czy mogę zapytać o informację?`},{who: `them`, it: `Sì, certo.`, pl: `Tak, oczywiście.`},{who: `you`, it: `Dov'è il Ponte di Rialto?`, pl: `Gdzie jest most Rialto?`},{who: `them`, it: `Vada dritto e poi giri a destra.`, pl: `Proszę iść prosto, a potem skręcić w prawo.`},{who: `you`, it: `È vicino?`, pl: `Czy to blisko?`},{who: `them`, it: `Sì, circa cinque minuti a piedi.`, pl: `Tak, około pięć minut pieszo.`},{who: `you`, it: `Devo attraversare il canale?`, pl: `Czy muszę przejść przez kanał?`},{who: `them`, it: `Sì, attraversi il piccolo ponte.`, pl: `Tak, proszę przejść przez mały most.`},{who: `you`, it: `Può mostrare sulla mappa?`, pl: `Czy może pan/pani pokazać na mapie?`},{who: `them`, it: `Certo, è qui.`, pl: `Oczywiście, to tutaj.`},{who: `you`, it: `Grazie, molto gentile.`, pl: `Dziękuję, bardzo uprzejmie.`},{who: `them`, it: `Prego, buona giornata.`, pl: `Nie ma za co, miłego dnia.`}]},{id: 4, title: `Kolacja w restauracji`, scene: `Jesteś w trattorii w Bolonii i chcesz zamówić kolację. Pytasz o rekomendację, zamawiasz makaron i prosisz o rachunek.`, lines: [{who: `them`, it: `Buonasera, avete una prenotazione?`, pl: `Dobry wieczór, czy mają państwo rezerwację?`},{who: `you`, it: `No, avete un tavolo per due?`, pl: `Nie, czy macie stolik dla dwóch osób?`},{who: `them`, it: `Sì, seguitemi, per favore.`, pl: `Tak, proszę za mną.`},{who: `you`, it: `Grazie, possiamo vedere il menu?`, pl: `Dziękuję, czy możemy zobaczyć menu?`},{who: `them`, it: `Certo, ecco il menu.`, pl: `Oczywiście, oto menu.`},{who: `you`, it: `Che cosa consiglia?`, pl: `Co pan/pani poleca?`},{who: `them`, it: `Consiglio le tagliatelle al ragù.`, pl: `Polecam tagliatelle z ragu.`},{who: `you`, it: `Perfetto, prendo quello.`, pl: `Świetnie, wezmę to.`},{who: `them`, it: `Da bere?`, pl: `Do picia?`},{who: `you`, it: `Una bottiglia d'acqua frizzante, per favore.`, pl: `Butelkę wody gazowanej, proszę.`},{who: `them`, it: `Va bene.`, pl: `Dobrze.`},{who: `you`, it: `Alla fine possiamo avere il conto?`, pl: `Na koniec czy możemy dostać rachunek?`}]},{id: 5, title: `Kupowanie biletów na transport`, scene: `Jesteś w Mediolanie i chcesz kupić bilety na metro do centrum. Automat jest niejasny, więc prosisz pracownika o pomoc.`, lines: [{who: `you`, it: `Scusi, dove compro un biglietto per la metro?`, pl: `Przepraszam, gdzie kupię bilet na metro?`},{who: `them`, it: `Può comprarlo alla macchina qui.`, pl: `Może pan/pani kupić go w automacie tutaj.`},{who: `you`, it: `Non capisco bene la macchina.`, pl: `Nie rozumiem dobrze automatu.`},{who: `them`, it: `Nessun problema, dove vuole andare?`, pl: `Żaden problem, dokąd chce pan/pani jechać?`},{who: `you`, it: `Voglio andare al Duomo.`, pl: `Chcę jechać do katedry Duomo.`},{who: `them`, it: `Allora prenda la linea rossa.`, pl: `W takim razie proszę wziąć czerwoną linię.`},{who: `you`, it: `Due biglietti, per favore.`, pl: `Dwa bilety, proszę.`},{who: `them`, it: `Sono quattro euro.`, pl: `To cztery euro.`},{who: `you`, it: `Posso pagare con carta?`, pl: `Czy mogę zapłacić kartą?`},{who: `them`, it: `Sì, inserisca la carta qui.`, pl: `Tak, proszę włożyć kartę tutaj.`},{who: `you`, it: `Questa è la fermata giusta?`, pl: `Czy to właściwy przystanek?`},{who: `them`, it: `Sì, scenda al Duomo.`, pl: `Tak, proszę wysiąść na Duomo.`}]},{id: 6, title: `Zakupy w sklepie z pamiątkami`, scene: `W małym sklepie w Rzymie oglądasz koszulkę i magnesy. Chcesz zapytać o cenę, rozmiar i płatność kartą.`, lines: [{who: `them`, it: `Buongiorno, posso aiutarla?`, pl: `Dzień dobry, czy mogę pomóc?`},{who: `you`, it: `Sì, quanto costa questa maglietta?`, pl: `Tak, ile kosztuje ta koszulka?`},{who: `them`, it: `Costa venti euro.`, pl: `Kosztuje dwadzieścia euro.`},{who: `you`, it: `Avete una taglia più grande?`, pl: `Czy macie większy rozmiar?`},{who: `them`, it: `Sì, abbiamo la taglia grande.`, pl: `Tak, mamy rozmiar duży.`},{who: `you`, it: `Avete questo modello in blu?`, pl: `Czy macie ten model w kolorze niebieskim?`},{who: `them`, it: `Sì, eccolo.`, pl: `Tak, oto on.`},{who: `you`, it: `Perfetto, lo prendo.`, pl: `Świetnie, wezmę to.`},{who: `them`, it: `Vuole anche un souvenir?`, pl: `Czy chce pan/pani też pamiątkę?`},{who: `you`, it: `Sì, due magneti, per favore.`, pl: `Tak, dwa magnesy, proszę.`},{who: `them`, it: `Possono essere questi?`, pl: `Czy mogą być te?`},{who: `you`, it: `Sì, e pago con carta.`, pl: `Tak, i zapłacę kartą.`}]},{id: 7, title: `W aptece`, scene: `W Neapolu boli cię głowa i szukasz prostego lekarstwa. Wchodzisz do apteki i wyjaśniasz objawy farmaceucie.`, lines: [{who: `them`, it: `Buongiorno, dica pure.`, pl: `Dzień dobry, proszę mówić.`},{who: `you`, it: `Buongiorno, ho mal di testa.`, pl: `Dzień dobry, boli mnie głowa.`},{who: `them`, it: `Ha anche la febbre?`, pl: `Czy ma pan/pani też gorączkę?`},{who: `you`, it: `No, non ho la febbre.`, pl: `Nie, nie mam gorączki.`},{who: `them`, it: `Ha allergie?`, pl: `Czy ma pan/pani alergie?`},{who: `you`, it: `Sono allergico alle noci, ma non ai farmaci.`, pl: `Jestem uczulony na orzechy, ale nie na leki.`},{who: `them`, it: `Va bene, questa medicina può aiutare.`, pl: `Dobrze, to lekarstwo może pomóc.`},{who: `you`, it: `Come devo prenderla?`, pl: `Jak mam je przyjmować?`},{who: `them`, it: `Una compressa dopo mangiato.`, pl: `Jedna tabletka po jedzeniu.`},{who: `you`, it: `Quanto costa?`, pl: `Ile kosztuje?`},{who: `them`, it: `Sono otto euro.`, pl: `To osiem euro.`},{who: `you`, it: `Grazie, pago in contanti.`, pl: `Dziękuję, płacę gotówką.`}]},{id: 8, title: `Krótka rozmowa z lokalną osobą`, scene: `Siedzisz na placu w Weronie i rozmawiasz z lokalną osobą przy sąsiednim stoliku. Chcesz powiedzieć, skąd jesteś, co robisz we Włoszech i zapytać o polecenia.`, lines: [{who: `you`, it: `Ciao, posso sedermi qui?`, pl: `Cześć, czy mogę tu usiąść?`},{who: `them`, it: `Sì, certo, prego.`, pl: `Tak, oczywiście, proszę.`},{who: `you`, it: `Grazie, questa piazza è bellissima.`, pl: `Dziękuję, ten plac jest przepiękny.`},{who: `them`, it: `Sì, è uno dei miei posti preferiti.`, pl: `Tak, to jedno z moich ulubionych miejsc.`},{who: `you`, it: `Vengo dalla Polonia.`, pl: `Pochodzę z Polski.`},{who: `them`, it: `Davvero? Sei in vacanza?`, pl: `Naprawdę? Jesteś na wakacjach?`},{who: `you`, it: `Sì, viaggio in Italia per due settimane.`, pl: `Tak, podróżuję po Włoszech przez dwa tygodnie.`},{who: `them`, it: `Ti piace Verona?`, pl: `Podoba ci się Werona?`},{who: `you`, it: `Molto, mi piace la città e il cibo.`, pl: `Bardzo, podoba mi się miasto i jedzenie.`},{who: `them`, it: `Devi visitare il teatro romano.`, pl: `Musisz odwiedzić teatr rzymski.`},{who: `you`, it: `Grazie del consiglio, ci andrò domani.`, pl: `Dziękuję za radę, pójdę tam jutro.`},{who: `them`, it: `Buon viaggio!`, pl: `Dobrej podróży!`}]}];